from datetime import datetime

from pydantic import Field

from maasservicelayer.models.base import ResourceBuilder, UNSET, Unset
from maasservicelayer.models.hardwareprofile import (
    HardwareAcceleratorGroup,
    HardwareNetworkGroup,
    HardwareStorageGroup,
)


class HardwareProfileBuilder(ResourceBuilder):
    """Autogenerated from utilities/generate_builders.py.

    You can still add your custom methods here, they won't be overwritten by
    the generated code.
    """

    accelerators: list[HardwareAcceleratorGroup] | Unset = Field(default=UNSET)
    architecture: str | Unset = Field(default=UNSET)
    cpu_cores: int | Unset = Field(default=UNSET)
    cpu_speed_mhz: int | Unset = Field(default=UNSET)
    created: datetime | Unset = Field(default=UNSET)
    disk_count: int | Unset = Field(default=UNSET)
    gpu_count: int | Unset = Field(default=UNSET)
    hardware_fingerprint: str | Unset = Field(default=UNSET)
    memory_mb: int | Unset = Field(default=UNSET)
    network: list[HardwareNetworkGroup] | Unset = Field(default=UNSET)
    nic_count: int | Unset = Field(default=UNSET)
    node_id: int | Unset = Field(default=UNSET)
    storage: list[HardwareStorageGroup] | Unset = Field(default=UNSET)
    system_product: str | None | Unset = Field(default=UNSET)
    system_vendor: str | None | Unset = Field(default=UNSET)
    total_storage_bytes: int | Unset = Field(default=UNSET)
    updated: datetime | Unset = Field(default=UNSET)
